insert into public.knowledge_points (id,name,summary,core_fact,category,published,version) values ('daxingqidao','大行其道','某种观点或事物流行，成为一种风尚','某种观点或事物流行，成为一种风尚','盛行泛滥',true,1),('weiranchengfeng','蔚然成风','一件事情逐渐发展盛行，形成良好风气','一件事情逐渐发展盛行，形成良好风气','盛行泛滥',true,1),('fangxingweiai','方兴未艾','事物正在蓬勃发展，一时不会终止','事物正在蓬勃发展，一时不会终止','兴起发展',true,1),('ruhuorutu','如火如荼','事物发展旺盛、气氛热烈','事物发展旺盛、气氛热烈','兴起发展',true,1),('rixinyueyi','日新月异','发展进步很快，不断出现新事物','发展进步很快，不断出现新事物','兴起发展',true,1),('gegudingxin','革故鼎新','除去旧的，建立新的','除去旧的，建立新的','文化革新',true,1),('tuichenchuxin','推陈出新','去掉旧事物的糟粕，创造出新的事物','去掉旧事物的糟粕，创造出新的事物','文化革新',true,1),('fengmaolinjiao','凤毛麟角','珍贵而稀少的人或事物','珍贵而稀少的人或事物','数量多少',true,1),('bushengmeiju','不胜枚举','数量很多，无法一一列举','数量很多，无法一一列举','数量多少',true,1),('qianyimohua','潜移默化','思想或性格在不知不觉中受到感染而变化','思想或性格在不知不觉中受到感染而变化','影响教育',true,1),('chizhiyiheng','持之以恒','长久坚持下去','长久坚持下去','坚持积累',true,1),('houjibofa','厚积薄发','长期充分积累后再稳健地发挥出来','长期充分积累后再稳健地发挥出来','坚持积累',true,1),('shebenzhuimo','舍本逐末','不抓根本环节，只在枝节上下功夫','不抓根本环节，只在枝节上下功夫','主次根本',true,1),('benmodaozhi','本末倒置','把主要和次要、根本和枝节的位置弄颠倒','把主要和次要、根本和枝节的位置弄颠倒','主次根本',true,1),('daxiangjingting','大相径庭','彼此相差很大，完全不同','彼此相差很大，完全不同','差距差别',true,1),('yicuerjiu','一蹴而就','事情轻而易举，一下子就能完成','事情轻而易举，一下子就能完成','迅速及时',true,1),('yizhenjianxue','一针见血','说话或文章直截了当，切中要害','说话或文章直截了当，切中要害','要害适当',true,1),('yinuoqianjin','一诺千金','说话算数，信用极高','说话算数，信用极高','诚信典故',true,1),('pofuchenzhou','破釜沉舟','下定决心，不顾一切干到底','下定决心，不顾一切干到底','战事策略',true,1),('zhishangtanbing','纸上谈兵','空谈理论，不能解决实际问题','空谈理论，不能解决实际问题','战事策略',true,1),('wangmeizhike','望梅止渴','用空想或假象安慰自己','用空想或假象安慰自己','方法眼光',true,1),('tuibisanshe','退避三舍','主动退让，不与人相争','主动退让，不与人相争','战事策略',true,1),('zhiluweima','指鹿为马','故意颠倒黑白，混淆是非','故意颠倒黑白，混淆是非','道理争议',true,1),('weiweijiuzhao','围魏救赵','攻击敌人后方以迫使其撤回的策略','攻击敌人后方以迫使其撤回的策略','战事策略',true,1),('maosuizijian','毛遂自荐','自告奋勇，主动推荐自己','自告奋勇，主动推荐自己','杰出优秀',true,1),('law-constitution','宪法地位','宪法是国家的根本法，具有最高的法律效力。','宪法是国家的根本法，具有最高的法律效力。','法律',true,1),('law-equality','法律面前平等','中华人民共和国公民在法律面前一律平等。','中华人民共和国公民在法律面前一律平等。','法律',true,1),('law-dignity','人格尊严','公民的人格尊严不受侵犯，禁止用任何方法侮辱、诽谤和诬告陷害公民。','公民的人格尊严不受侵犯，禁止用任何方法侮辱、诽谤和诬告陷害公民。','法律',true,1),('law-vote','选举权','年满十八周岁的中国公民，除依法被剥夺政治权利者外，都有选举权和被选举权。','年满十八周岁的中国公民，除依法被剥夺政治权利者外，都有选举权和被选举权。','法律',true,1),('law-civil-adult','完全民事行为能力','十八周岁以上的自然人是成年人，具有完全民事行为能力。','十八周岁以上的自然人是成年人，具有完全民事行为能力。','法律',true,1),('law-civil-young','无民事行为能力人','不满八周岁的未成年人为无民事行为能力人。','不满八周岁的未成年人为无民事行为能力人。','法律',true,1),('law-civil-minor','限制民事行为能力人','八周岁以上的未成年人为限制民事行为能力人。','八周岁以上的未成年人为限制民事行为能力人。','法律',true,1),('law-property','物权保护','国家、集体、私人的物权和其他权利人的物权受法律平等保护，任何组织或者个人不得侵犯。','国家、集体、私人的物权和其他权利人的物权受法律平等保护，任何组织或者个人不得侵犯。','法律',true,1),('law-contract','合同成立','当事人采用合同书形式订立合同的，自当事人均签名、盖章或者按指印时合同成立。','当事人采用合同书形式订立合同的，自当事人均签名、盖章或者按指印时合同成立。','法律',true,1),('law-consumer','消费者权益','消费者享有知悉其购买、使用的商品或者接受的服务真实情况的权利。','消费者享有知悉其购买、使用的商品或者接受的服务真实情况的权利。','法律',true,1),('law-labor-hours','工作时间','国家实行劳动者每日工作时间不超过八小时、平均每周工作时间不超过四十四小时的工时制度。','国家实行劳动者每日工作时间不超过八小时、平均每周工作时间不超过四十四小时的工时制度。','法律',true,1),('law-labor-rest','休息日','用人单位应当保证劳动者每周至少休息一日。','用人单位应当保证劳动者每周至少休息一日。','法律',true,1),('law-criminal-age','刑事责任年龄','已满十六周岁的人犯罪，应当负刑事责任。','已满十六周岁的人犯罪，应当负刑事责任。','法律',true,1),('law-criminal-special','特殊刑责年龄','已满十四周岁不满十六周岁的人，对故意杀人等法定严重犯罪负刑事责任。','已满十四周岁不满十六周岁的人，对故意杀人等法定严重犯罪负刑事责任。','法律',true,1),('law-defense','正当防卫','为了使国家、公共利益、本人或者他人的人身、财产和其他权利免受正在进行的不法侵害，而采取制止不法侵害的行为，造成损害的，属于正当防卫。','为了使国家、公共利益、本人或者他人的人身、财产和其他权利免受正在进行的不法侵害，而采取制止不法侵害的行为，造成损害的，属于正当防卫。','法律',true,1),('law-emergency','紧急避险','为了使国家、公共利益、本人或者他人的人身、财产和其他权利免受正在发生的危险，不得已采取的紧急避险行为，造成损害的，不负刑事责任。','为了使国家、公共利益、本人或者他人的人身、财产和其他权利免受正在发生的危险，不得已采取的紧急避险行为，造成损害的，不负刑事责任。','法律',true,1),('law-admin-reconsider','行政复议','公民、法人或者其他组织认为行政行为侵犯其合法权益，可以依法申请行政复议。','公民、法人或者其他组织认为行政行为侵犯其合法权益，可以依法申请行政复议。','法律',true,1),('law-admin-litigation','行政诉讼','公民、法人或者其他组织认为行政机关和行政机关工作人员的行政行为侵犯其合法权益，有权依法向人民法院提起诉讼。','公民、法人或者其他组织认为行政机关和行政机关工作人员的行政行为侵犯其合法权益，有权依法向人民法院提起诉讼。','法律',true,1),('law-state-comp','国家赔偿','国家机关和国家机关工作人员违法行使职权侵犯公民、法人和其他组织合法权益造成损害的，受害人有依照法律取得国家赔偿的权利。','国家机关和国家机关工作人员违法行使职权侵犯公民、法人和其他组织合法权益造成损害的，受害人有依照法律取得国家赔偿的权利。','法律',true,1),('law-environment','环境保护','国家保护和改善生活环境和生态环境，防治污染和其他公害。','国家保护和改善生活环境和生态环境，防治污染和其他公害。','法律',true,1),('law-education','受教育权','中华人民共和国公民有受教育的权利和义务。','中华人民共和国公民有受教育的权利和义务。','法律',true,1),('law-marriage','婚姻自由','婚姻、家庭、母亲和儿童受国家保护，禁止破坏婚姻自由。','婚姻、家庭、母亲和儿童受国家保护，禁止破坏婚姻自由。','法律',true,1),('law-national-flag','国旗','中华人民共和国国旗是五星红旗。','中华人民共和国国旗是五星红旗。','法律',true,1),('law-national-emblem','国徽','中华人民共和国国徽中间是五星照耀下的天安门，周围是谷穗和齿轮。','中华人民共和国国徽中间是五星照耀下的天安门，周围是谷穗和齿轮。','法律',true,1),('law-rule','依法治国','中华人民共和国实行依法治国，建设社会主义法治国家。','中华人民共和国实行依法治国，建设社会主义法治国家。','法律',true,1),('hist-xia','夏朝','夏朝通常被视为中国史书中记载的第一个世袭制王朝。','夏朝通常被视为中国史书中记载的第一个世袭制王朝。','历史文化',true,1),('hist-qin','秦朝统一','秦始皇于公元前221年统一六国，建立秦朝。','秦始皇于公元前221年统一六国，建立秦朝。','历史文化',true,1),('hist-han','丝绸之路','张骞出使西域为汉代丝绸之路的开通奠定了基础。','张骞出使西域为汉代丝绸之路的开通奠定了基础。','历史文化',true,1),('hist-three','三国时期','三国时期通常指魏、蜀、吴三国鼎立的历史阶段。','三国时期通常指魏、蜀、吴三国鼎立的历史阶段。','历史文化',true,1),('hist-sui','隋朝运河','隋朝大运河沟通海河、黄河、淮河、长江和钱塘江五大水系。','隋朝大运河沟通海河、黄河、淮河、长江和钱塘江五大水系。','历史文化',true,1),('hist-tang','贞观之治','贞观之治是唐太宗李世民在位时期出现的政治清明、经济恢复发展的局面。','贞观之治是唐太宗李世民在位时期出现的政治清明、经济恢复发展的局面。','历史文化',true,1),('hist-song','活字印刷','北宋毕昇发明泥活字印刷术。','北宋毕昇发明泥活字印刷术。','历史文化',true,1),('hist-yuan','行省制度','元朝在地方实行行省制度，对后世地方行政制度影响深远。','元朝在地方实行行省制度，对后世地方行政制度影响深远。','历史文化',true,1),('hist-ming','郑和下西洋','郑和下西洋发生在明朝前期。','郑和下西洋发生在明朝前期。','历史文化',true,1),('hist-qing','康乾盛世','康乾盛世通常指清朝康熙、雍正、乾隆时期社会经济发展较快的阶段。','康乾盛世通常指清朝康熙、雍正、乾隆时期社会经济发展较快的阶段。','历史文化',true,1),('hist-reform','戊戌变法','戊戌变法发生于1898年，主张变法图强。','戊戌变法发生于1898年，主张变法图强。','历史文化',true,1),('hist-xinhai','辛亥革命','辛亥革命推翻了清朝统治，结束了中国延续两千多年的君主专制制度。','辛亥革命推翻了清朝统治，结束了中国延续两千多年的君主专制制度。','历史文化',true,1),('hist-four-inventions','四大发明','造纸术、印刷术、火药和指南针通常被称为中国古代四大发明。','造纸术、印刷术、火药和指南针通常被称为中国古代四大发明。','历史文化',true,1),('hist-oracle','甲骨文','甲骨文是刻在龟甲和兽骨上的文字，是汉字早期形态的重要实物资料。','甲骨文是刻在龟甲和兽骨上的文字，是汉字早期形态的重要实物资料。','历史文化',true,1),('hist-ru','儒家','儒家学派的创始人是孔子。','儒家学派的创始人是孔子。','历史文化',true,1),('hist-dao','道家','道家学派代表人物包括老子和庄子。','道家学派代表人物包括老子和庄子。','历史文化',true,1),('hist-mo','墨家','墨家学派的代表人物是墨子，主张兼爱、非攻。','墨家学派的代表人物是墨子，主张兼爱、非攻。','历史文化',true,1),('hist-legalism','法家','法家代表人物包括韩非，强调以法治国。','法家代表人物包括韩非，强调以法治国。','历史文化',true,1),('hist-poetry','诗经','《诗经》是中国最早的一部诗歌总集。','《诗经》是中国最早的一部诗歌总集。','历史文化',true,1),('hist-chuci','楚辞','《楚辞》以屈原作品为主，具有鲜明的楚地文化特色。','《楚辞》以屈原作品为主，具有鲜明的楚地文化特色。','历史文化',true,1),('hist-tang-poet','诗仙','李白被后人称为“诗仙”。','李白被后人称为“诗仙”。','历史文化',true,1),('hist-dufu','诗圣','杜甫被后人称为“诗圣”。','杜甫被后人称为“诗圣”。','历史文化',true,1),('hist-red','红楼梦','《红楼梦》的作者通常署为曹雪芹。','《红楼梦》的作者通常署为曹雪芹。','历史文化',true,1),('hist-water','水浒传','《水浒传》的作者通常署为施耐庵。','《水浒传》的作者通常署为施耐庵。','历史文化',true,1),('hist-journey','西游记','《西游记》的作者通常署为吴承恩。','《西游记》的作者通常署为吴承恩。','历史文化',true,1),('science-water','水的化学式','水的化学式是H₂O。','水的化学式是H₂O。','科技生活',true,1),('science-air','空气成分','干燥空气中体积分数最大的成分是氮气。','干燥空气中体积分数最大的成分是氮气。','科技生活',true,1),('science-light','光合作用','绿色植物通过光合作用利用光能，把二氧化碳和水转化为有机物，并释放氧气。','绿色植物通过光合作用利用光能，把二氧化碳和水转化为有机物，并释放氧气。','科技生活',true,1),('science-respiration','呼吸作用','生物呼吸作用会分解有机物并释放能量。','生物呼吸作用会分解有机物并释放能量。','科技生活',true,1),('science-cell','细胞','细胞是构成生物体结构和功能的基本单位。','细胞是构成生物体结构和功能的基本单位。','科技生活',true,1),('science-dna','遗传物质','DNA是主要的遗传物质。','DNA是主要的遗传物质。','科技生活',true,1),('science-virus','病毒','病毒不能独立完成生命活动，必须寄生在活细胞内。','病毒不能独立完成生命活动，必须寄生在活细胞内。','科技生活',true,1),('science-vaccine','疫苗','疫苗通过激发人体免疫反应，帮助机体获得针对特定病原体的保护。','疫苗通过激发人体免疫反应，帮助机体获得针对特定病原体的保护。','科技生活',true,1),('science-gravity','重力','地球附近物体受到的重力方向大致竖直向下。','地球附近物体受到的重力方向大致竖直向下。','科技生活',true,1),('science-inertia','惯性','物体保持原来运动状态不变的性质叫惯性。','物体保持原来运动状态不变的性质叫惯性。','科技生活',true,1),('science-force','力的作用效果','力可以改变物体的运动状态，也可以使物体发生形变。','力可以改变物体的运动状态，也可以使物体发生形变。','科技生活',true,1),('science-electric','串联电路','串联电路中各处电流相等。','串联电路中各处电流相等。','科技生活',true,1),('science-parallel','并联电路','并联电路中各支路两端电压相等。','并联电路中各支路两端电压相等。','科技生活',true,1),('science-conductor','导体','金属通常是良好的导体，因为其中有可以自由移动的电子。','金属通常是良好的导体，因为其中有可以自由移动的电子。','科技生活',true,1),('science-sound','声音传播','声音传播需要介质，真空中不能传声。','声音传播需要介质，真空中不能传声。','科技生活',true,1),('science-moon','月相','月相变化主要是由于月球绕地球运动时日、地、月三者相对位置不断改变。','月相变化主要是由于月球绕地球运动时日、地、月三者相对位置不断改变。','科技生活',true,1),('science-solar','太阳系','太阳是太阳系的中心天体。','太阳是太阳系的中心天体。','科技生活',true,1),('science-seasons','四季成因','地球四季变化与地轴倾斜和地球绕太阳公转有关。','地球四季变化与地轴倾斜和地球绕太阳公转有关。','科技生活',true,1),('science-ozone','臭氧层','平流层臭氧层能吸收部分太阳紫外线。','平流层臭氧层能吸收部分太阳紫外线。','科技生活',true,1),('science-greenhouse','温室气体','二氧化碳是重要的温室气体之一。','二氧化碳是重要的温室气体之一。','科技生活',true,1),('science-burn','燃烧条件','可燃物燃烧通常需要与氧气接触并达到着火点。','可燃物燃烧通常需要与氧气接触并达到着火点。','科技生活',true,1),('science-acidbase','酸碱性','pH小于7的溶液通常呈酸性，pH大于7的溶液通常呈碱性。','pH小于7的溶液通常呈酸性，pH大于7的溶液通常呈碱性。','科技生活',true,1),('science-recycle','可回收物','废纸、塑料、金属和玻璃等适宜回收利用的生活废弃物属于可回收物。','废纸、塑料、金属和玻璃等适宜回收利用的生活废弃物属于可回收物。','科技生活',true,1),('science-firstaid','心肺复苏','发现无反应且无正常呼吸者，应在确保环境安全后尽快呼救并实施心肺复苏。','发现无反应且无正常呼吸者，应在确保环境安全后尽快呼救并实施心肺复苏。','科技生活',true,1),('science-fire','火灾逃生','发生火灾时应优先选择安全疏散，不乘坐普通电梯逃生。','发生火灾时应优先选择安全疏散，不乘坐普通电梯逃生。','科技生活',true,1),('geo-capital','首都','中华人民共和国首都是北京。','中华人民共和国首都是北京。','地理国情',true,1),('geo-area','陆地面积','中国陆地国土面积约960万平方千米。','中国陆地国土面积约960万平方千米。','地理国情',true,1),('geo-coast','海陆位置','中国位于亚洲东部、太平洋西岸。','中国位于亚洲东部、太平洋西岸。','地理国情',true,1),('geo-neighbors','陆地邻国','中国陆地边界与14个国家相接。','中国陆地边界与14个国家相接。','地理国情',true,1),('geo-provinces','省级行政区','中国有34个省级行政区，包括省、自治区、直辖市和特别行政区。','中国有34个省级行政区，包括省、自治区、直辖市和特别行政区。','地理国情',true,1),('geo-river','长江','长江是中国第一大河，发源于青藏高原。','长江是中国第一大河，发源于青藏高原。','地理国情',true,1),('geo-yellow','黄河','黄河发源于青藏高原，是中华民族的母亲河之一。','黄河发源于青藏高原，是中华民族的母亲河之一。','地理国情',true,1),('geo-plateau','青藏高原','青藏高原平均海拔高，被称为“世界屋脊”。','青藏高原平均海拔高，被称为“世界屋脊”。','地理国情',true,1),('geo-basin','塔里木盆地','塔里木盆地是中国面积最大的盆地。','塔里木盆地是中国面积最大的盆地。','地理国情',true,1),('geo-desert','塔克拉玛干沙漠','塔克拉玛干沙漠位于塔里木盆地内，是中国最大的沙漠。','塔克拉玛干沙漠位于塔里木盆地内，是中国最大的沙漠。','地理国情',true,1),('geo-mountain','喜马拉雅山脉','喜马拉雅山脉是世界上最高大的山脉。','喜马拉雅山脉是世界上最高大的山脉。','地理国情',true,1),('geo-everest','珠穆朗玛峰','珠穆朗玛峰是世界最高峰，位于中国与尼泊尔边境。','珠穆朗玛峰是世界最高峰，位于中国与尼泊尔边境。','地理国情',true,1),('geo-climate','季风气候','中国东部地区受季风影响显著，夏季普遍高温多雨。','中国东部地区受季风影响显著，夏季普遍高温多雨。','地理国情',true,1),('geo-monsoonline','季风区分界','大兴安岭—阴山—贺兰山一线大致是中国季风区与非季风区的分界