insert into public.questions (id,knowledge_id,level_id,question_type,stem,options,correct_answer,explanation,difficulty,published,version) values ('common-law-environment','law-environment','common-2','single_choice','关于“环境保护”，下列说法正确的是？','{"questionId":"common-law-environment","knowledgeId":"law-environment","type":"single_choice","stem":"关于“环境保护”，下列说法正确的是？","options":[{"id":"A","text":"公民、法人或者其他组织认为行政行为侵犯其合法权益，可以依法申请行政复议。"},{"id":"B","text":"国家保护和改善生活环境和生态环境，防治污染和其他公害。"},{"id":"C","text":"消费者享有知悉其购买、使用的商品或者接受的服务真实情况的权利。"},{"id":"D","text":"公民的人格尊严不受侵犯，禁止用任何方法侮辱、诽谤和诬告陷害公民。"}]}'::jsonb,'"B"'::jsonb,'{"summary":"国家保护和改善生活环境和生态环境，防治污染和其他公害。","whyCorrect":"“环境保护”的正确表述是：国家保护和改善生活环境和生态环境，防治污染和其他公害。 依据：《中华人民共和国宪法》。","whyUserAnswerWrong":"干扰项混淆了相近概念、条件或对应关系，应回到准确表述判断。","commonMistake":"注意区分“环境保护”的适用条件与相近常识。","memoryTip":"环境保护是国家基本职责。"}',5,true,1),('common-law-education','law-education','common-2','single_choice','关于“受教育权”，下列说法正确的是？','{"questionId":"common-law-education","knowledgeId":"law-education","type":"single_choice","stem":"关于“受教育权”，下列说法正确的是？","options":[{"id":"A","text":"公民、法人或者其他组织认为行政机关和行政机关工作人员的行政行为侵犯其合法权益，有权依法向人民法院提起诉讼。"},{"id":"B","text":"年满十八周岁的中国公民，除依法被剥夺政治权利者外，都有选举权和被选举权。"},{"id":"C","text":"国家实行劳动者每日工作时间不超过八小时、平均每周工作时间不超过四十四小时的工时制度。"},{"id":"D","text":"中华人民共和国公民有受教育的权利和义务。"}]}'::jsonb,'"D"'::jsonb,'{"summary":"中华人民共和国公民有受教育的权利和义务。","whyCorrect":"“受教育权”的正确表述是：中华人民共和国公民有受教育的权利和义务。 依据：《中华人民共和国宪法》。","whyUserAnswerWrong":"干扰项混淆了相近概念、条件或对应关系，应回到准确表述判断。","commonMistake":"注意区分“受教育权”的适用条件与相近常识。","memoryTip":"受教育既是权利也是义务。"}',1,true,1),('common-law-marriage','law-marriage','common-2','single_choice','关于“婚姻自由”，下列说法正确的是？','{"questionId":"common-law-marriage","knowledgeId":"law-marriage","type":"single_choice","stem":"关于“婚姻自由”，下列说法正确的是？","options":[{"id":"A","text":"用人单位应当保证劳动者每周至少休息一日。"},{"id":"B","text":"十八周岁以上的自然人是成年人，具有完全民事行为能力。"},{"id":"C","text":"婚姻、家庭、母亲和儿童受国家保护，禁止破坏婚姻自由。"},{"id":"D","text":"国家机关和国家机关工作人员违法行使职权侵犯公民、法人和其他组织合法权益造成损害的，受害人有依照法律取得国家赔偿的权利。"}]}'::jsonb,'"